import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{r as s,o as t,c as d,e,f as n,b as c,d as o}from"./app-f06160db.js";const l={},r=e("h1",{id:"青龙面板",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#青龙面板","aria-hidden":"true"},"#"),n(),e("strong",null,"青龙面板")],-1),p={class:"hint-container tip"},g=e("p",{class:"hint-container-title"},"提示",-1),u=e("p",null,[e("strong",null,"使用青龙面板挂载脚本，自动化执行京东定时任务，自动获取京豆")],-1),m={href:"https://github.com/whyour/qinglong",target:"_blank",rel:"noopener noreferrer"},v=o(`<h2 id="一、安装" tabindex="-1"><a class="header-anchor" href="#一、安装" aria-hidden="true">#</a> <strong>一、安装</strong></h2><p>使用CentOS 7的系统，笔者使用的是CentOS 7.9。<strong>如果使用的是云服务器，需要在安全组中开放5700端口。</strong></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>yum update <span class="token parameter variable">-y</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>安装docker：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 一直按enter键可以默认所有操作</span>
<span class="token function">bash</span> <span class="token operator">&lt;</span><span class="token punctuation">(</span><span class="token function">curl</span> <span class="token parameter variable">-sSL</span> https://gitee.com/SuperManito/LinuxMirrors/raw/main/DockerInstallation.sh<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container warning"><p class="hint-container-title">注意</p><p>不要使用github的qinglong最新版本，因为跟脚本的适配性不够好，很多脚本会执行失败。<strong>推荐2.11.X版本，笔者使用的是2.11.0版本，可以使用下面的命令自动安装。</strong></p></div><p>安装qinglong的docker镜像：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 一直按enter键可以默认所有操作</span>
<span class="token function">wget</span> <span class="token parameter variable">-q</span> https://yanyu.ltd/https://raw.githubusercontent.com/yanyuwangluo/VIP/main/Scripts/sh/ql.sh <span class="token parameter variable">-O</span> ql.sh <span class="token operator">&amp;&amp;</span> <span class="token function">bash</span> ql.sh
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>安装完毕后，在浏览器访问<code>ip:5700</code>，即可进入青龙面板的图形化界面。配置自己的账号密码，如果有通知的需要，来配置相关信息。</p><h2 id="二、qinglong中的配置" tabindex="-1"><a class="header-anchor" href="#二、qinglong中的配置" aria-hidden="true">#</a> <strong>二、qinglong中的配置</strong></h2><h3 id="拉脚本库" tabindex="-1"><a class="header-anchor" href="#拉脚本库" aria-hidden="true">#</a> <strong>拉脚本库</strong></h3><div class="hint-container tip"><p class="hint-container-title">提示</p><p>有很多京东的脚本库，但是许多脚本库的活动都停止了，或者已经跑不起来了，这里笔者经过查找和踩坑，推荐一个目前还在更新的脚本库，作者是faker。</p></div><p>拉取脚本库的命令：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment">#Faker2 助力池版【安全本地sign防CK泄漏】</span>
ql repo https://git.metauniverse-cn.com/https://github.com/shufflewzc/faker2.git <span class="token string">&quot;jd_|jx_|gua_|jddj_|jdCookie&quot;</span> <span class="token string">&quot;activity|backUp&quot;</span> <span class="token string">&quot;^jd[^_]|USER|function|utils|sendNotify|ZooFaker_Necklace.js|JDJRValidator_|sign_graphics_validate|ql|JDSignValidator|magic|depend|h5sts&quot;</span> <span class="token string">&quot;main&quot;</span>

<span class="token comment">#Faker3 内部互助版【安全本地sign防CK泄漏】</span>
ql repo https://git.metauniverse-cn.com/https://github.com/shufflewzc/faker3.git <span class="token string">&quot;jd_|jx_|gua_|jddj_|jdCookie&quot;</span> <span class="token string">&quot;activity|backUp&quot;</span> <span class="token string">&quot;^jd[^_]|USER|function|utils|sendNotify|ZooFaker_Necklace.js|JDJRValidator_|sign_graphics_validate|ql|JDSignValidator|magic|depend|h5sts&quot;</span> <span class="token string">&quot;main&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container warning"><p class="hint-container-title">注意</p><p>【注意】不可同时拉Faker2与Faker3仓库，同时拉多个集合库容易黑ip，保留一个即可。</p></div><p>在拉库之前，需要修改配置文件中的一个字段。点击配置文件，设置GithubProxyUrl=&quot;&quot;。</p><p>进入面板后，点击<code>定时任务</code>，点击<code>新建任务</code>，然后在命令那里输入拉取脚本库的命令，定时规则笔者设置的是<code>45 23 * * *</code>，即每天的23：45再次执行该脚本拉取脚本库。</p><figure><img src="https://personal-site-pictures.oss-cn-beijing.aliyuncs.com/img/image-20221217002751812.png" alt="image-20221217002751812" tabindex="0" loading="lazy"><figcaption>image-20221217002751812</figcaption></figure><p>之后点击下图按钮，执行该脚本拉取库中的脚本。</p><figure><img src="https://personal-site-pictures.oss-cn-beijing.aliyuncs.com/img/image-20221217002855893.png" alt="image-20221217002855893" tabindex="0" loading="lazy"><figcaption>image-20221217002855893</figcaption></figure><h3 id="配置环境变量" tabindex="-1"><a class="header-anchor" href="#配置环境变量" aria-hidden="true">#</a> <strong>配置环境变量</strong></h3><p>点击青龙面板的依赖管理——&gt;新建依赖——&gt;选择NodeJs、自动拆分选择是，复制以下的依赖填到名称里——&gt;点击确定，等待安装完成。如下图所示：</p><figure><img src="https://personal-site-pictures.oss-cn-beijing.aliyuncs.com/img/image-20221217003212599.png" alt="image-20221217003212599" tabindex="0" loading="lazy"><figcaption>image-20221217003212599</figcaption></figure><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>crypto-js
prettytable
dotenv
jsdom
date-fns
tough-cookie
tslib
ws@7.4.3
ts-md5
jsdom -g
jieba
fs
form-data
json5
global-agent
png-js
@types/node
require
typescript
js-base64
axios
moment
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>同理，Python下有：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>requests
canvas
ping3
jieba
PyExecJS
aiohttp
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>同理，Linux下有：</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>bizCode
bizMsg
lxm
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="hint-container tip"><p class="hint-container-title">提示</p><p>安装时间较长，耐心等待一下。如果最终提示安装失败，可以点击bug的那个按钮进行重新安装。</p></div><h2 id="三、配置jd账号cookie" tabindex="-1"><a class="header-anchor" href="#三、配置jd账号cookie" aria-hidden="true">#</a> <strong>三、配置JD账号Cookie</strong></h2><p>一切就绪后，接下来就是最重要的环节：配置我们的京东账号信息。</p><p>打开Chrome浏览器，输入<code>jd.com</code>，按照下图步骤切换为手机视图。</p><figure><img src="https://pic4.zhimg.com/80/v2-218c5d33ae742e0448a78e907233e973_720w.webp" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><p>我们可以选择iPhoneX视图，刷新页面后发现地址栏变为手机版的京东首页地址<code>m.jd.com</code></p><figure><img src="https://personal-site-pictures.oss-cn-beijing.aliyuncs.com/img/v2-5bec51cd4a9b4964788479c2a75d28f4_720w.webp" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><p>正常按照手机号+验证码登录</p><figure><img src="https://personal-site-pictures.oss-cn-beijing.aliyuncs.com/img/v2-5925b549502d4ff5af2eae4d496cfe47_720w.webp" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><p>登录过后，这个时候就需要从cookie中查看<code>pt_</code>开头的两个关键配置：<code>pt_key</code>,<code>pt_pin</code></p><figure><img src="https://personal-site-pictures.oss-cn-beijing.aliyuncs.com/img/v2-6dc96dc7a8b2a0dea6fdc2baa96bbaae_720w.webp" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><p>把对应的value拷贝出来，整理格式如下</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>pt_key=xxxx;pt_pin=xxxx;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>接下来回到青龙面板，新建环境变量，名称为<code>JD_COOKIE</code>，值为上面整理的文本。</p><figure><img src="https://personal-site-pictures.oss-cn-beijing.aliyuncs.com/img/v2-37d79a6fd07980a90ec09dfca35d243a_720w.webp" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><p>经过以上步骤，京东账号的信息就配置完毕了。</p><h2 id="四、测试" tabindex="-1"><a class="header-anchor" href="#四、测试" aria-hidden="true">#</a> <strong>四、测试</strong></h2><p>保存过后，我们就可以从脚本列表中，手动执行任意一个任务脚本来验证一下。</p><p>可以执行<code>京东多合一签到</code>脚本，发现签到成功，说明配置成功。</p><p>笔者写下这篇教程已经配置完成三天了，收益大概是40-70京豆不等。</p>`,48);function b(h,f){const i=s("ExternalLinkIcon");return t(),d("div",null,[r,e("div",p,[g,u,e("p",null,[e("a",m,[n("qinglong"),c(i)]),n("是github的开源项目，支持多种语言的定时任务管理软件，我们的京东脚本就定时地、自动化地跑在该平台上。")])]),v])}const k=a(l,[["render",b],["__file","qinglong.html.vue"]]);export{k as default};
